INSERT INTO news_article (title, content, summary, source_id, language, category_id, publish_time, status, hot_score, view_count) VALUES
('OpenAI 正式发布 GPT-6 新一代大语言模型', 'OpenAI 今日宣布发布 GPT-6，这是其最新一代大语言模型。该模型在推理能力、多模态理解和代码生成方面取得重大突破，多项基准测试超越人类水平。', 'OpenAI 发布 GPT-6 新一代大语言模型，在推理和多模态能力上取得重大突破。', 1, 'zh-CN', 4, NOW(), 1, 98, 1520),
('Apple 推出 M4 芯片搭载全新 MacBook Pro', 'Apple 今日发布搭载 M4 芯片的新款 MacBook Pro，采用 2nm 工艺，CPU 性能提升 50%，GPU 性能提升 80%，电池续航达到 24 小时。', 'Apple 推出 M4 芯片新款 MacBook Pro，性能大幅提升。', 2, 'zh-CN', 3, NOW(), 1, 92, 2340),
('中国新能源车出口量创历史新高', '据海关总署数据，2026 年上半年中国新能源汽车出口量突破 300 万辆，同比增长 45%，主要出口市场包括欧洲、东南亚和南美洲。', '中国新能源车出口量创历史新高，上半年突破 300 万辆。', 3, 'zh-CN', 5, NOW(), 1, 88, 980),
('美联储维持利率不变 降息预期升温', '美联储在最新议息会议上决定维持联邦基金利率不变，但暗示可能在 9 月开始降息。市场对降息的预期大幅升温，美股三大指数集体收涨。', '美联储维持利率不变，暗示 9 月可能开始降息。', 1, 'zh-CN', 5, NOW(), 1, 85, 3100),
('DeepSeek 推出下一代推理模型 R2', 'DeepSeek 发布全新 R2 推理模型，采用混合专家架构，在数学推理和代码生成方面超越 GPT-6，且推理成本仅为竞争对手的 1/10。', 'DeepSeek 发布 R2 推理模型，性能和成本均具有竞争力。', 4, 'zh-CN', 4, NOW(), 1, 95, 4200),
('全球首座商用核聚变电站破土动工', '由 ITER 组织和多家私营企业联合建设的全球首座商用核聚变电站在法国南部正式破土动工，预计 2035 年并网发电，标志着人类能源史上的里程碑。', '全球首座商用核聚变电站在法国破土动工。', 2, 'zh-CN', 3, NOW(), 1, 90, 1890),
('NVIDIA 市值突破 5 万亿美元', 'NVIDIA 股价持续上涨，市值突破 5 万亿美元，成为全球市值最高的公司。AI 芯片需求持续旺盛，Blackwell 架构芯片供不应求。', 'NVIDIA 市值突破 5 万亿美元，成为全球市值最高公司。', 4, 'zh-CN', 4, NOW(), 1, 96, 5600),
('欧盟通过全球首部 AI 监管法案修正案', '欧盟议会投票通过 AI 监管法案修正案，进一步加强对通用人工智能和前沿 AI 模型的监管要求，包括强制性安全评估、透明度和问责机制。', '欧盟通过全球首部 AI 监管法案修正案，加强 AI 监管。', 1, 'zh-CN', 4, NOW(), 1, 80, 1120);
